diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..e078aab620b7 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5153,6 +5153,120 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
       return new ICmpInst(ICmpInst::ICMP_SLT, SRem->getOperand(1),
                           Constant::getNullValue(SRem->getType()));
     }
+
+  }
+
+  // Fold: (X /[us] C) < X --> X > 0 (for C > 1)
+  // Similar folds for other predicates
+  if (BO0 && (BO0->getOpcode() == Instruction::SDiv ||
+              BO0->getOpcode() == Instruction::UDiv)) {
+    Value *Dividend = BO0->getOperand(0);
+    Value *Divisor = BO0->getOperand(1);
+    const APInt *DivisorC;
+    // Check if divisor is a constant > 1
+    if (Dividend == Op1 && match(Divisor, m_APInt(DivisorC)) &&
+        ((BO0->getOpcode() == Instruction::SDiv && DivisorC->isStrictlyPositive() &&
+          !DivisorC->isOne()) ||
+         (BO0->getOpcode() == Instruction::UDiv &&
+          !DivisorC->isZero() && !DivisorC->isOne()))) {
+      Constant *Zero = Constant::getNullValue(Dividend->getType());
+      switch (Pred) {
+      case ICmpInst::ICMP_SLT:
+        if (BO0->getOpcode() == Instruction::SDiv)
+          return new ICmpInst(ICmpInst::ICMP_SGT, Dividend, Zero);
+        if (BO0->getOpcode() == Instruction::UDiv)
+          return new ICmpInst(ICmpInst::ICMP_SGT, Dividend, Zero);
+        break;
+      case ICmpInst::ICMP_SLE:
+        if (BO0->getOpcode() == Instruction::SDiv)
+          return new ICmpInst(ICmpInst::ICMP_SGE, Dividend, Zero);
+        if (BO0->getOpcode() == Instruction::UDiv)
+          return new ICmpInst(ICmpInst::ICMP_SGE, Dividend, Zero);
+        break;
+      case ICmpInst::ICMP_ULE:
+        if (BO0->getOpcode() == Instruction::UDiv)
+          return replaceInstUsesWith(I, ConstantInt::getTrue(I.getType()));
+        break;
+      case ICmpInst::ICMP_SGT:
+        if (BO0->getOpcode() == Instruction::SDiv)
+          return new ICmpInst(ICmpInst::ICMP_SLT, Dividend, Zero);
+        LLVM_FALLTHROUGH;
+      case ICmpInst::ICMP_UGT:
+        if (BO0->getOpcode() == Instruction::UDiv)
+          return replaceInstUsesWith(I, ConstantInt::getFalse(I.getType()));
+        break;
+      case ICmpInst::ICMP_SGE:
+        if (BO0->getOpcode() == Instruction::SDiv)
+          return new ICmpInst(ICmpInst::ICMP_SLE, Dividend, Zero);
+        LLVM_FALLTHROUGH;
+      case ICmpInst::ICMP_UGE:
+        if (BO0->getOpcode() == Instruction::UDiv)
+          return new ICmpInst(ICmpInst::ICMP_EQ, Dividend, Zero);
+        break;
+      case ICmpInst::ICMP_EQ:
+        return new ICmpInst(ICmpInst::ICMP_EQ, Dividend, Zero);
+      case ICmpInst::ICMP_NE:
+        return new ICmpInst(ICmpInst::ICMP_NE, Dividend, Zero);
+      default:
+        break;
+      }
+    }
+  }
+  // Fold: X < (X /[us] C) --> X < 0 (for C > 1)
+  if (BO1 && (BO1->getOpcode() == Instruction::SDiv ||
+              BO1->getOpcode() == Instruction::UDiv)) {
+    Value *Dividend = BO1->getOperand(0);
+    Value *Divisor = BO1->getOperand(1);
+    const APInt *DivisorC;
+    // Check if divisor is a constant > 1
+    if (Dividend == Op0 && match(Divisor, m_APInt(DivisorC)) &&
+        ((BO1->getOpcode() == Instruction::SDiv && DivisorC->isStrictlyPositive() &&
+          !DivisorC->isOne()) ||
+         (BO1->getOpcode() == Instruction::UDiv &&
+          !DivisorC->isZero() && !DivisorC->isOne()))) {
+      Constant *Zero = Constant::getNullValue(Dividend->getType());
+      switch (Pred) {
+      case ICmpInst::ICMP_SLT:
+        if (BO1->getOpcode() == Instruction::SDiv)
+          return new ICmpInst(ICmpInst::ICMP_SLT, Dividend, Zero);
+        LLVM_FALLTHROUGH;
+      case ICmpInst::ICMP_ULT:
+        if (BO1->getOpcode() == Instruction::UDiv)
+          return replaceInstUsesWith(I, ConstantInt::getFalse(I.getType()));
+        break;
+      case ICmpInst::ICMP_SLE:
+        if (BO1->getOpcode() == Instruction::SDiv)
+          return new ICmpInst(ICmpInst::ICMP_SLE, Dividend, Zero);
+        LLVM_FALLTHROUGH;
+      case ICmpInst::ICMP_ULE:
+        if (BO1->getOpcode() == Instruction::UDiv)
+          return new ICmpInst(ICmpInst::ICMP_EQ, Dividend, Zero);
+        break;
+      case ICmpInst::ICMP_SGT:
+        if (BO1->getOpcode() == Instruction::SDiv)
+          return new ICmpInst(ICmpInst::ICMP_SGT, Dividend, Zero);
+        LLVM_FALLTHROUGH;
+      case ICmpInst::ICMP_UGT:
+        if (BO1->getOpcode() == Instruction::UDiv)
+          return new ICmpInst(ICmpInst::ICMP_NE, Dividend, Zero);
+        break;
+      case ICmpInst::ICMP_SGE:
+        if (BO1->getOpcode() == Instruction::SDiv)
+          return replaceInstUsesWith(I, ConstantInt::getTrue(I.getType()));
+        LLVM_FALLTHROUGH;
+      case ICmpInst::ICMP_UGE:
+        if (BO1->getOpcode() == Instruction::UDiv ||
+            (BO1->getOpcode() == Instruction::SDiv && !I.isUnsigned()))
+          return replaceInstUsesWith(I, ConstantInt::getTrue(I.getType()));
+        break;
+      case ICmpInst::ICMP_EQ:
+        return new ICmpInst(ICmpInst::ICMP_EQ, Dividend, Zero);
+      case ICmpInst::ICMP_NE:
+        return new ICmpInst(ICmpInst::ICMP_NE, Dividend, Zero);
+      default:
+        break;
+      }
+    }
   }

   if (BO0 && BO1 && BO0->getOpcode() == BO1->getOpcode() &&
@@ -7158,7 +7272,173 @@ Instruction *InstCombinerImpl::foldICmpCommutative(ICmpInst::Predicate Pred,
       }
     }
   }
+  // icmp (sdiv X, C), X  where C > 1
+  // For signed division by C > 1:
+  //   (X /s C) <s X   --> X >s 0
+  //   (X /s C) <=s X  --> X >=s 0
+  //   (X /s C) >s X   --> X <s 0
+  //   (X /s C) >=s X  --> X <=s 0
+  //   (X /s C) == X   --> false
+  //   (X /s C) != X   --> true
+  {
+    Value *X;
+    const APInt *C;
+    if (match(Op0, m_SDiv(m_Value(X), m_APInt(C))) && Op1 == X &&
+        C->isStrictlyPositive() && !C->isOne()) {
+      switch (Pred) {
+      case ICmpInst::ICMP_SLT:
+        // (X / C) < X  -->  X > 0
+        return new ICmpInst(ICmpInst::ICMP_SGT, X,
+                            ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_SLE:
+        // (X / C) <= X  -->  X >= 0
+        return new ICmpInst(ICmpInst::ICMP_SGE, X,
+                            ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_SGT:
+        // (X / C) > X  -->  X < 0
+        return new ICmpInst(ICmpInst::ICMP_SLT, X,
+                            ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_SGE:
+        // (X / C) >= X  -->  X <= 0
+        return new ICmpInst(ICmpInst::ICMP_SLE, X,
+                            ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_EQ:
+        // (X / C) == X  -->  false
+        return replaceInstUsesWith(CxtI,
+                                   ConstantInt::getFalse(CxtI.getType()));
+      case ICmpInst::ICMP_NE:
+        // (X / C) != X  -->  true
+        return replaceInstUsesWith(CxtI,
+                                   ConstantInt::getTrue(CxtI.getType()));
+      default:
+        break;
+      }
+    }
+  }
+
+  // icmp (udiv X, C), X  where C > 1
+  // For unsigned division by C > 1:
+  //   (X /u C) <u X   --> X != 0
+  //   (X /u C) <=u X  --> true
+  //   (X /u C) >u X   --> false
+  //   (X /u C) >=u X  --> X == 0
+  //   (X /u C) == X   --> X == 0
+  //   (X /u C) != X   --> X != 0
+  {
+    Value *X;
+    const APInt *C;
+    if (match(Op0, m_UDiv(m_Value(X), m_APInt(C))) && Op1 == X &&
+        !C->isOne()) {
+      switch (Pred) {
+      case ICmpInst::ICMP_ULT:
+        // (X / C) <u X  -->  X != 0
+        return new ICmpInst(ICmpInst::ICMP_NE, X,
+                            ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_ULE:
+        // (X / C) <=u X  -->  true
+        return replaceInstUsesWith(CxtI,
+                                   ConstantInt::getTrue(CxtI.getType()));
+      case ICmpInst::ICMP_UGT:
+        // (X / C) >u X  -->  false
+        return replaceInstUsesWith(CxtI,
+                                   ConstantInt::getFalse(CxtI.getType()));
+      case ICmpInst::ICMP_UGE:
+        // (X / C) >=u X  -->  X == 0
+        return new ICmpInst(ICmpInst::ICMP_EQ, X,
+                            ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_EQ:
+        // (X / C) == X  -->  X == 0
+        return new ICmpInst(ICmpInst::ICMP_EQ, X,
+                            ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_NE:
+        // (X / C) != X  -->  X != 0
+        return new ICmpInst(ICmpInst::ICMP_NE, X,
+                            ConstantInt::get(X->getType(), 0));
+      default:
+        break;
+      }
+    }
+  }

+  // icmp (lshr X, C), X  where C > 0
+  // For logical right shift by C > 0:
+  //   (X >>u C) == X   --> X == 0
+  //   (X >>u C) != X   --> X != 0
+  //   (X >>u C) <s X   --> false (lshr result is >= 0, and < X only when X > result)
+  //   (X >>u C) <=s X  --> X >= 0
+  //   (X >>u C) >s X   --> X < 0
+  //   (X >>u C) >=s X  --> X <= 0
+  {
+    Value *X;
+    const APInt *C;
+    if (match(Op0, m_LShr(m_Value(X), m_APInt(C))) && Op1 == X &&
+        !C->isZero()) {
+      switch (Pred) {
+      case ICmpInst::ICMP_EQ:
+        return new ICmpInst(ICmpInst::ICMP_EQ, X,
+                            ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_NE:
+        return new ICmpInst(ICmpInst::ICMP_NE, X,
+                            ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_SLT:
+        return replaceInstUsesWith(CxtI,
+                                   ConstantInt::getFalse(CxtI.getType()));
+      case ICmpInst::ICMP_SLE:
+        // X >= 0
+        return new ICmpInst(ICmpInst::ICMP_SGE, X,
+                            ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_SGT:
+        // X < 0
+        return new ICmpInst(ICmpInst::ICMP_SLT, X,
+                            ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_SGE:
+        // X <= 0
+        return new ICmpInst(ICmpInst::ICMP_SLE, X,
+                            ConstantInt::get(X->getType(), 0));
+      default:
+        break;
+      }
+    }
+  }
+
+  // icmp (ashr X, C), X  where C > 0
+  // For arithmetic right shift by C > 0:
+  //   (X >>s C) >=s X  --> X <= 0
+  //   (X >>s C) <s X   --> X > 0
+  //   (X >>s C) == X   --> X == 0 (for small C) or more complex
+  //   (X >>s C) != X   --> X != 0 (for small C) or more complex
+  {
+    Value *X;
+    const APInt *C;
+    if (match(Op0, m_AShr(m_Value(X), m_APInt(C))) && Op1 == X &&
+        !C->isZero()) {
+      switch (Pred) {
+      case ICmpInst::ICMP_SGE:
+        // X <= 0
+        return new ICmpInst(ICmpInst::ICMP_SLE, X,
+                            ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_SLT:
+        // X > 0
+        return new ICmpInst(ICmpInst::ICMP_SGT, X,
+                            ConstantInt::get(X->getType(), 0));
+      default:
+        break;
+      }
+    }
+  }
+
+  // Cross-signedness cases for udiv with signed compare
+  // icmp (udiv X, C), X where C > 1:
+  //   (X /u C) <s X  --> X >s 0
+  {
+    Value *X;
+    const APInt *C;
+    if (match(Op0, m_UDiv(m_Value(X), m_APInt(C))) && Op1 == X &&
+        !C->isOne() && Pred == ICmpInst::ICMP_SLT) {
+      return new ICmpInst(ICmpInst::ICMP_SGT, X,
+                          ConstantInt::get(X->getType(), 0));
+    }
+  }
   const SimplifyQuery Q = SQ.getWithInstruction(&CxtI);
   if (Value *V = foldICmpWithLowBitMaskedVal(Pred, Op0, Op1, Q, *this))
     return replaceInstUsesWith(CxtI, V);

